import visualSearchService from './backend/services/aiService.js';

const testOpenAI = async () => {
    try {
        console.log('🧪 Testing OpenAI Visual Search Service...');

        // Create a minimal valid JPEG buffer (1x1 pixel white image)
        // Base64 for 1x1 white pixel jpeg
        const base64Image = "";
        const dummyBuffer = Buffer.from(base64Image, 'base64');

        console.log(`📦 Created dummy image buffer (${dummyBuffer.length} bytes)`);

        console.log('🚀 Sending to OpenAI...');
        const result = await visualSearchService.classifyImage(dummyBuffer);

        console.log('✅ Result received:', result);
    } catch (error) {
        console.error('❌ Service failed:', error);
        if (error.response) {
            console.error('Data:', error.response.data);
            console.error('Status:', error.response.status);
        }
    }
};

testOpenAI();
